CREATE OR REPLACE FUNCTION fpa_get_crem_groupno (as_memno text) RETURNS varchar AS $body$
DECLARE

ls_group_no sc_mem_m_membership_registered.member_group_no%type;

BEGIN

    begin
        select member_group_no   into STRICT ls_group_no
        from sc_mem_m_membership_registered@db_crem
        where 1=1
        and member_status_code = '0'
        and crem_memno = as_memno
;
    exception
    when others then return null;
    end;

  return ls_group_no;
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
